### Option 1: Python Visualization (Simple)

This script creates a basic house using geometric primitives (a cube for the body and a pyramid for the roof).

```python
import matplotlib.pyplot as plt
from mpl_toolkits.mplot3d import Axes3D
import numpy as np

def create_house():
    fig = plt.figure(figsize=(10, 8))
    ax = fig.add_subplot(111, projection='3d')

    # --- House Body (Cube) ---
    # Dimensions: x, y, z
    x = np.array([-1, 1, 1, -1, -1])
    y = np.array([0, 0, 0, 0, 0])
    z = np.array([0, 0, 2, 2, 0])
    ax.plot_trisurf(x, y, z, color='orange', alpha=0.8, linewidth=0)

    # --- House Roof (Pyramid) ---
    # Base points
    base_x = np.array([-1, 1, 1, -1])
    base_y = np.array([0, 0, 0, 0])
    base_z = np.array([2, 2, 2, 2])

    # Apex point
    apex_x = np.array([0])
    apex_y = np.array([2])
    apex_z = np.array([3])

    # Combine base and apex for the trisurf
    roof_x = np.concatenate([base_x, apex_x])
    roof_y = np.concatenate([base_y, apex_y])
    roof_z = np.concatenate([base_z, apex_z])

    ax.plot_trisurf(roof_x, roof_y, roof_z, color='red', alpha=0.8, linewidth=0)

    # --- Door ---
    # Simple rectangle on the front face
    door_x = np.array([-0.4, 0.4, 0.4, -0.4])
    door_y = np.array([0, 0, 0, 0])
    door_z = np.array([0, 0, 1.5, 1.5])
    ax.plot_trisurf(door_x, door_y, door_z, color='brown', alpha=0.9, linewidth=0)

    # --- Windows ---
    # Left Window
    win1_x = np.array([-0.6, -0.2, -0.2, -0.6])
    win1_y = np.array([0, 0, 0, 0])
    win1_z = np.array([0, 0, 1.5, 1.5])
    ax.plot_trisurf(win1_x, win1_y, win1_z, color='lightblue', alpha=0.6, linewidth=0)

    # Right Window
    win2_x = np.array([0.2, 0.6, 0.6, 0.2])
    win2_y = np.array([0, 0, 0, 0])
    win2_z = np.array([0, 0, 1.5, 1.5])
    ax.plot_trisurf(win2_x, win2_y, win2_z, color='lightblue', alpha=0.6, linewidth=0)

    # Labels and Limits
    ax.set_xlabel('X')
    ax.set_ylabel('Y')
    ax.set_zlabel('Z')
    ax.set_xlim(-2, 2)
    ax.set_ylim(-1, 4)
    ax.set_zlim(-1, 4)
    ax.view_init(elev=20, azim=45)

    plt.title("3D House Model (Python)")
    plt.show()

if __name__ == "__main__":
    create_house()
```

